import DebugLog from '../debug/DebugLog.js';
import SceneManager from '../core/SceneManager.js';
import EventBus from '../core/EventBus.js';
import UIPanel from '../ui/UIPanel.js';
import OnlineLobbyPanel from '../ui/OnlineLobbyPanel.js';

// ─────────────────────────────────────────────────────────────────────────────
// MainMenuPanel  (extends UIPanel)
// HTML/CSS panel for the main menu overlay
// ─────────────────────────────────────────────────────────────────────────────

class MainMenuPanel extends UIPanel {
  constructor() {
    super('panel-main-menu', {
      classes: ['spellroads-panel', 'main-menu-panel'],
    });

    this._buttons = [];
    this._focusIndex = 0;
    this._keyHandler = this._onKey.bind(this);
  }

  build(buttonDefs) {
    this.el.innerHTML = '';

    // Inner wrapper to control width and centering
    const inner = document.createElement('div');
    inner.className = 'main-menu-inner';

    // Title
    const title = document.createElement('h1');
    title.className = 'main-menu-title';
    title.textContent = 'SPELLROADS';
    inner.appendChild(title);

    // Studio byline
    const byline = document.createElement('p');
    byline.className = 'main-menu-byline';
    byline.textContent = 'by Waystone Interactive';
    inner.appendChild(byline);

    // Button container
    const btnContainer = document.createElement('nav');
    btnContainer.className = 'main-menu-buttons';
    btnContainer.setAttribute('role', 'navigation');
    btnContainer.setAttribute('aria-label', 'Main menu');

    this._buttons = [];
    buttonDefs.forEach((def, idx) => {
      const btn = document.createElement('button');
      btn.className = 'spellroads-btn main-menu-btn';
      btn.textContent = def.label;
      btn.dataset.index = String(idx);
      btn.setAttribute('type', 'button');

      btn.addEventListener('click', () => {
        this._focusIndex = idx;
        this._updateFocus();
        def.action();
      });

      btn.addEventListener('focus', () => {
        this._focusIndex = idx;
        this._updateFocus();
      });

      btnContainer.appendChild(btn);
      this._buttons.push(btn);
    });

    inner.appendChild(btnContainer);

    // Version
    const version = document.createElement('p');
    version.className = 'main-menu-version';
    version.textContent = 'Version 0.1.0';
    inner.appendChild(version);

    this.el.appendChild(inner);

    // Keyboard/gamepad navigation
    document.addEventListener('keydown', this._keyHandler);

    return this;
  }

  focusFirst() {
    this._focusIndex = 0;
    this._updateFocus();
    if (this._buttons[0]) {
      this._buttons[0].focus();
    }
  }

  _updateFocus() {
    this._buttons.forEach((btn, i) => {
      btn.classList.toggle('focused', i === this._focusIndex);
      btn.setAttribute('tabindex', i === this._focusIndex ? '0' : '-1');
    });
  }

  _onKey(e) {
    if (!this._visible) return;

    switch (e.key) {
      case 'ArrowDown':
      case 's':
      case 'S': {
        e.preventDefault();
        this._focusIndex = (this._focusIndex + 1) % this._buttons.length;
        this._updateFocus();
        this._buttons[this._focusIndex].focus();
        break;
      }
      case 'ArrowUp':
      case 'w':
      case 'W': {
        e.preventDefault();
        this._focusIndex =
          (this._focusIndex - 1 + this._buttons.length) % this._buttons.length;
        this._updateFocus();
        this._buttons[this._focusIndex].focus();
        break;
      }
      case 'Enter':
      case 'e':
      case 'E': {
        e.preventDefault();
        if (this._buttons[this._focusIndex]) {
          this._buttons[this._focusIndex].click();
        }
        break;
      }
      default:
        break;
    }
  }

  destroy() {
    document.removeEventListener('keydown', this._keyHandler);
    this._buttons = [];
    this.hide();
    if (this.el && this.el.parentNode) {
      this.el.remove();
    }
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// MainMenuScene
// ─────────────────────────────────────────────────────────────────────────────

export default class MainMenuScene {
  constructor() {
    this._panel = null;
    this._bgEl = null;
    this._activeModal = null;
    /** @type {OnlineLobbyPanel|null} */
    this._onlineLobbyPanel = null;
  }

  async init() {
    DebugLog.info('[boot] MainMenuScene starting');

    // ── CSS starfield background ─────────────────────────────────────────────
    this._buildCssBg();

    // ── HTML/CSS panel ───────────────────────────────────────────────────────
    this._injectStyles();
    this._buildPanel();

    // ── Expose scene on window.__debug ───────────────────────────────────────
    if (!window.__debug) {
      window.__debug = {};
    }
    window.__debug.currentScene = 'mainMenu';

    DebugLog.info('[boot] MainMenuScene ready');
  }

  // ── CSS procedural starfield background ─────────────────────────────────────

  _buildCssBg() {
    const bg = document.createElement('div');
    bg.id = 'mm-bg';

    const STAR_COUNT = 80;
    for (let i = 0; i < STAR_COUNT; i++) {
      const span = document.createElement('span');
      const left = (Math.random() * 100).toFixed(2);
      const top = (Math.random() * 100).toFixed(2);
      const op = (Math.random() * 0.6 + 0.2).toFixed(2);
      const size = (Math.random() * 2 + 2).toFixed(1);
      const delay = (Math.random() * 4).toFixed(2);
      span.style.cssText =
        `left:${left}%;top:${top}%;--op:${op};width:${size}px;height:${size}px;animation-delay:${delay}s`;
      bg.appendChild(span);
    }

    const mount = document.getElementById('ui-overlay') ?? document.body;
    mount.appendChild(bg);
    this._bgEl = bg;
  }

  // ── HTML/CSS panel ──────────────────────────────────────────────────────────

  _buildPanel() {
    this._panel = new MainMenuPanel();

    const buttons = [
      {
        label: 'New Game',
        action: () => {
          DebugLog.info('[boot] New Game clicked');
          SceneManager.transition('charCreate');
        },
      },
      {
        label: 'Load Game',
        action: async () => {
          DebugLog.info('[boot] Load Game clicked');
          const saveSystem = window.__saveSystem;
          if (!saveSystem) return;

          const slots = saveSystem.getSlotInfo().filter(s => !s.empty);
          if (slots.length === 0) {
            import('../ui/Toast.js').then(m =>
              m.default.show('No saved games found.', { type: 'warn', duration: 2500 })
            );
            return;
          }

          // Load most recent non-auto slot, fall back to auto
          const slot = slots.find(s => s.slot !== 'auto') ?? slots[0];
          const result = await saveSystem.load(slot.slot);
          if (result.ok) {
            import('../ui/Toast.js').then(m =>
              m.default.show('Game loaded!', { type: 'success' })
            );
            // Navigate to world map after load
            import('../core/SceneManager.js').then(m =>
              m.default.transition('worldMap')
            );
          } else {
            import('../ui/Toast.js').then(m =>
              m.default.show(result.message, { type: 'error' })
            );
          }
        },
      },
      {
        label: 'Online Co-op',
        action: () => {
          DebugLog.info('[boot] Online Co-op clicked');
          this._showOnlineLobby();
        },
      },
      {
        label: 'Settings',
        action: () => {
          DebugLog.info('[boot] Settings clicked');
          this._showSettingsModal();
        },
      },
      {
        label: 'Credits',
        action: () => {
          DebugLog.info('[boot] Credits clicked');
          this._showCreditsModal();
        },
      },
    ];

    this._panel.build(buttons);
    this._panel.show();
    this._panel.focusFirst();
  }

  // ── Modals ──────────────────────────────────────────────────────────────────

  /**
   * Create and show a lightweight modal overlay.
   * Returns the modal root element so the caller can populate it.
   * The modal is dismissed by clicking the backdrop or the close button.
   *
   * @param {string} id — Unique element id for the modal root
   * @returns {HTMLElement} The inner content box
   */
  _createModal(id) {
    // Remove any existing modal with this id
    const existing = document.getElementById(id);
    if (existing) existing.remove();

    const backdrop = document.createElement('div');
    backdrop.id = id;
    backdrop.style.cssText = [
      'position:fixed',
      'inset:0',
      'z-index:350',
      'display:flex',
      'align-items:center',
      'justify-content:center',
      'background:rgba(0,0,0,0.72)',
      'pointer-events:all',
    ].join(';');

    const box = document.createElement('div');
    box.style.cssText = [
      'position:relative',
      'width:min(480px,90vw)',
      'max-height:80vh',
      'overflow-y:auto',
      'background:#0e0b09',
      'border:1px solid rgba(200,160,32,0.35)',
      'border-radius:4px',
      'padding:clamp(20px,4vw,36px)',
      'color:#e8d5b0',
      'font-family:"Segoe UI",system-ui,sans-serif',
      'box-shadow:0 8px 48px rgba(0,0,0,0.9)',
    ].join(';');

    const closeBtn = document.createElement('button');
    closeBtn.type = 'button';
    closeBtn.textContent = '\u00D7';
    closeBtn.setAttribute('aria-label', 'Close');
    closeBtn.style.cssText = [
      'position:absolute',
      'top:12px',
      'right:12px',
      'background:none',
      'border:none',
      'color:#a09070',
      'font-size:1.4rem',
      'cursor:pointer',
      'min-width:44px',
      'min-height:44px',
      'display:flex',
      'align-items:center',
      'justify-content:center',
      'border-radius:3px',
      'line-height:1',
    ].join(';');

    const dismiss = () => {
      backdrop.remove();
      this._activeModal = null;
    };

    closeBtn.addEventListener('click', dismiss);
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) dismiss();
    });
    document.addEventListener('keydown', function escHandler(e) {
      if (e.key === 'Escape') {
        dismiss();
        document.removeEventListener('keydown', escHandler);
      }
    });

    box.appendChild(closeBtn);
    backdrop.appendChild(box);

    const mount = document.getElementById('ui-overlay') ?? document.body;
    mount.appendChild(backdrop);

    this._activeModal = backdrop;
    return box;
  }

  _showOnlineLobby() {
    if (!this._onlineLobbyPanel) {
      this._onlineLobbyPanel = new OnlineLobbyPanel();
    }
    this._onlineLobbyPanel.show();
  }

  _showSettingsModal() {
    const box = this._createModal('mm-settings-modal');

    const title = document.createElement('h2');
    title.textContent = 'Settings';
    title.style.cssText = 'margin:0 0 20px;font-size:1.2rem;letter-spacing:.12em;text-transform:uppercase;color:#c8a020;';
    box.appendChild(title);

    // Master volume
    const makeSlider = (label, storageKey, defaultVal) => {
      const row = document.createElement('div');
      row.style.cssText = 'display:flex;align-items:center;gap:12px;margin-bottom:14px;';

      const lbl = document.createElement('label');
      lbl.textContent = label;
      lbl.style.cssText = 'flex:0 0 140px;font-size:.85rem;color:#c8a020;letter-spacing:.06em;';

      const slider = document.createElement('input');
      slider.type = 'range';
      slider.min = '0';
      slider.max = '100';
      slider.step = '1';
      slider.value = String(Number(localStorage.getItem(storageKey) ?? defaultVal));
      slider.style.cssText = 'flex:1;accent-color:#c8a020;min-height:44px;cursor:pointer;';

      const val = document.createElement('span');
      val.textContent = slider.value;
      val.style.cssText = 'flex:0 0 36px;text-align:right;font-size:.85rem;color:#a09070;';

      slider.addEventListener('input', () => {
        val.textContent = slider.value;
        localStorage.setItem(storageKey, slider.value);
        // Notify audio manager if present
        EventBus.emit('settings:volume', { key: storageKey, value: Number(slider.value) / 100 });
      });

      row.appendChild(lbl);
      row.appendChild(slider);
      row.appendChild(val);
      return row;
    };

    box.appendChild(makeSlider('Master Volume', 'vol_master', 80));
    box.appendChild(makeSlider('Music Volume', 'vol_music', 70));
    box.appendChild(makeSlider('SFX Volume', 'vol_sfx', 80));

    // Fog of War toggle
    const fogRow = document.createElement('div');
    fogRow.style.cssText = 'display:flex;align-items:center;gap:12px;margin-bottom:14px;';
    const fogLbl = document.createElement('label');
    fogLbl.textContent = 'Fog of War';
    fogLbl.style.cssText = 'flex:0 0 140px;font-size:.85rem;color:#c8a020;letter-spacing:.06em;cursor:pointer;';
    const fogCheck = document.createElement('input');
    fogCheck.type = 'checkbox';
    fogCheck.checked = localStorage.getItem('fog_of_war') !== 'false';
    fogCheck.style.cssText = 'width:20px;height:20px;accent-color:#c8a020;cursor:pointer;min-height:unset;';
    fogCheck.addEventListener('change', () => {
      localStorage.setItem('fog_of_war', String(fogCheck.checked));
      EventBus.emit('settings:fog', { enabled: fogCheck.checked });
    });
    fogLbl.htmlFor = 'setting-fog-check';
    fogCheck.id = 'setting-fog-check';
    fogRow.appendChild(fogLbl);
    fogRow.appendChild(fogCheck);
    box.appendChild(fogRow);

    DebugLog.info('[boot] Settings modal opened');
  }

  _showCreditsModal() {
    const box = this._createModal('mm-credits-modal');

    const title = document.createElement('h2');
    title.textContent = 'Credits';
    title.style.cssText = 'margin:0 0 20px;font-size:1.2rem;letter-spacing:.12em;text-transform:uppercase;color:#c8a020;';
    box.appendChild(title);

    const credits = [
      { role: 'Game Design & Development', name: 'Waystone Interactive' },
      { role: 'Engine', name: 'PixiJS v8' },
      { role: 'Audio', name: 'Howler.js' },
      { role: 'Build', name: 'Vite' },
      { role: 'Testing', name: 'Playwright' },
    ];

    credits.forEach(({ role, name }) => {
      const row = document.createElement('div');
      row.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:10px;font-size:.85rem;border-bottom:1px solid rgba(90,74,53,0.4);padding-bottom:10px;';
      const roleEl = document.createElement('span');
      roleEl.textContent = role;
      roleEl.style.color = '#a09070';
      const nameEl = document.createElement('span');
      nameEl.textContent = name;
      nameEl.style.color = '#c8a020';
      row.appendChild(roleEl);
      row.appendChild(nameEl);
      box.appendChild(row);
    });

    const footer = document.createElement('p');
    footer.textContent = 'Spellroads v0.1.0 — All rights reserved.';
    footer.style.cssText = 'margin-top:16px;font-size:.72rem;color:#706050;text-align:center;letter-spacing:.06em;';
    box.appendChild(footer);

    DebugLog.info('[boot] Credits modal opened');
  }

  // ── Inline styles ───────────────────────────────────────────────────────────

  _injectStyles() {
    const STYLE_ID = 'spellroads-main-menu-style';
    if (document.getElementById(STYLE_ID)) return;

    const style = document.createElement('style');
    style.id = STYLE_ID;
    style.textContent = `
      /* ── CSS starfield background ────────────────────────────────────── */
      #mm-bg {
        position: fixed;
        inset: 0;
        z-index: 0;
        background: radial-gradient(ellipse at center, #1e1208 0%, #0a0808 70%);
        pointer-events: none;
      }

      #mm-bg span {
        position: absolute;
        width: 2px;
        height: 2px;
        border-radius: 50%;
        background: #c8a020;
        animation: mm-twinkle 3s ease-in-out infinite;
      }

      @keyframes mm-twinkle {
        0%, 100% { opacity: var(--op); transform: scale(1); }
        50%       { opacity: calc(var(--op) * 0.3); transform: scale(0.6); }
      }

      /* ── Main Menu Panel ─────────────────────────────────────────────── */
      #panel-main-menu {
        position: fixed;
        inset: 0;
        z-index: 200;
        display: none;
        align-items: center;
        justify-content: center;
        background: transparent;
        pointer-events: none;
      }

      #panel-main-menu.visible {
        display: flex;
      }

      .main-menu-inner {
        width: min(400px, 90vw);
        padding: clamp(24px, 5vw, 48px) clamp(20px, 4vw, 40px);
        background: rgba(10, 8, 8, 0.82);
        border: 1px solid rgba(200, 160, 32, 0.3);
        border-radius: 4px;
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 0;
        pointer-events: auto;
        box-shadow:
          0 0 40px rgba(0, 0, 0, 0.8),
          inset 0 0 60px rgba(200, 160, 32, 0.04);
      }

      /* Portrait mobile: slightly looser layout */
      @media (max-width: 767px) and (orientation: portrait) {
        .main-menu-inner {
          width: 90vw;
          padding: 28px 20px;
        }
      }

      /* Landscape mobile: reduce vertical padding */
      @media (max-width: 1023px) and (orientation: landscape) {
        .main-menu-inner {
          padding: 16px 32px;
          gap: 0;
        }
      }

      /* ── Title ──────────────────────────────────────────────────────── */
      .main-menu-title {
        margin: 0 0 4px 0;
        font-family: "Segoe UI", system-ui, sans-serif;
        font-size: clamp(1.8rem, 5vw, 2.8rem);
        font-weight: 800;
        letter-spacing: 0.2em;
        color: #c8a020;
        text-shadow:
          0 0 20px rgba(200, 160, 32, 0.7),
          0 2px 4px rgba(0, 0, 0, 0.8);
        text-align: center;
        line-height: 1.1;
      }

      /* ── Byline ─────────────────────────────────────────────────────── */
      .main-menu-byline {
        margin: 0 0 clamp(24px, 4vh, 36px) 0;
        font-family: "Segoe UI", system-ui, sans-serif;
        font-size: clamp(0.65rem, 1.5vw, 0.8rem);
        letter-spacing: 0.12em;
        color: #6a5a3a;
        text-align: center;
        text-transform: uppercase;
      }

      /* ── Button list ────────────────────────────────────────────────── */
      .main-menu-buttons {
        display: flex;
        flex-direction: column;
        align-items: stretch;
        width: 100%;
        gap: 10px;
        margin-bottom: clamp(20px, 3vh, 28px);
      }

      /* ── Individual buttons ─────────────────────────────────────────── */
      .main-menu-btn {
        min-height: 44px;
        padding: 10px 20px;
        font-family: "Segoe UI", system-ui, sans-serif;
        font-size: clamp(0.85rem, 2vw, 1rem);
        font-weight: 600;
        letter-spacing: 0.06em;
        color: #c8a020;
        background: rgba(200, 160, 32, 0.06);
        border: 1px solid rgba(200, 160, 32, 0.25);
        border-radius: 3px;
        cursor: pointer;
        transition:
          background 0.15s ease,
          border-color 0.15s ease,
          color 0.15s ease,
          box-shadow 0.15s ease;
        text-align: center;
        outline: none;
        -webkit-tap-highlight-color: transparent;
      }

      .main-menu-btn:hover,
      .main-menu-btn:focus,
      .main-menu-btn.focused {
        background: rgba(200, 160, 32, 0.14);
        border-color: rgba(200, 160, 32, 0.65);
        color: #e8c040;
        box-shadow: 0 0 12px rgba(200, 160, 32, 0.25);
      }

      .main-menu-btn:active {
        background: rgba(200, 160, 32, 0.22);
        transform: translateY(1px);
      }

      /* ── Version label ──────────────────────────────────────────────── */
      .main-menu-version {
        margin: 0;
        font-family: "Segoe UI", system-ui, sans-serif;
        font-size: clamp(0.6rem, 1.2vw, 0.72rem);
        color: #3a3020;
        letter-spacing: 0.08em;
        text-align: center;
      }
    `;
    document.head.appendChild(style);
  }

  // ── Teardown ────────────────────────────────────────────────────────────────

  destroy() {
    DebugLog.info('[boot] MainMenuScene destroy');

    // Dismiss any open modal
    if (this._activeModal) {
      this._activeModal.remove();
      this._activeModal = null;
    }

    // Close online lobby panel if open
    if (this._onlineLobbyPanel) {
      this._onlineLobbyPanel.hide();
      this._onlineLobbyPanel = null;
    }

    // Remove keyboard listener and DOM panel
    if (this._panel) {
      this._panel.destroy();
      this._panel = null;
    }

    // Remove CSS starfield background
    if (this._bgEl) {
      this._bgEl.remove();
      this._bgEl = null;
    }

    if (window.__debug && window.__debug.currentScene === 'mainMenu') {
      window.__debug.currentScene = null;
    }
  }
}
