/**
 * OnlineLobbyPanel — HTML/CSS panel for online co-op lobby.
 *
 * Tabs:
 *   [Host Game] — Creates a room, shows the room code, waits for guest, enables Start.
 *   [Join Game] — Input field for room code + Join button.
 *
 * Wires to OnlineCoopSystem for all WebSocket communication.
 *
 * @module OnlineLobbyPanel
 */

import DebugLog from '../debug/DebugLog.js';
import OnlineCoopSystem from '../systems/OnlineCoopSystem.js';

// ─────────────────────────────────────────────────────────────────────────────
// Styles (injected once)
// ─────────────────────────────────────────────────────────────────────────────

const STYLE_ID = 'spellroads-online-lobby-style';

function injectStyles() {
  if (document.getElementById(STYLE_ID)) return;
  const style = document.createElement('style');
  style.id = STYLE_ID;
  style.textContent = `
    /* ── Online Lobby Backdrop ─────────────────────────────────────────────── */
    #online-lobby-backdrop {
      position: fixed;
      inset: 0;
      z-index: 350;
      display: none;
      align-items: center;
      justify-content: center;
      background: rgba(0,0,0,0.80);
      pointer-events: all;
    }

    #online-lobby-backdrop.visible {
      display: flex;
    }

    /* ── Panel box ────────────────────────────────────────────────────────── */
    .online-lobby-box {
      position: relative;
      width: min(480px, 92vw);
      background: #0e0b09;
      border: 1px solid rgba(200,160,32,0.35);
      border-radius: 4px;
      padding: clamp(20px,4vw,36px);
      color: #e8d5b0;
      font-family: "Segoe UI", system-ui, sans-serif;
      box-shadow: 0 8px 48px rgba(0,0,0,0.9);
    }

    .online-lobby-close {
      position: absolute;
      top: 10px;
      right: 10px;
      background: none;
      border: none;
      color: #a09070;
      font-size: 1.4rem;
      cursor: pointer;
      min-width: 44px;
      min-height: 44px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 3px;
      line-height: 1;
    }

    .online-lobby-close:hover { color: #e8c040; }

    /* ── Title ────────────────────────────────────────────────────────────── */
    .online-lobby-title {
      margin: 0 0 16px;
      font-size: 1.1rem;
      font-weight: 700;
      letter-spacing: .14em;
      text-transform: uppercase;
      color: #c8a020;
    }

    /* ── Tabs ─────────────────────────────────────────────────────────────── */
    .online-lobby-tabs {
      display: flex;
      gap: 6px;
      margin-bottom: 20px;
    }

    .online-lobby-tab {
      flex: 1;
      padding: 8px 0;
      background: rgba(200,160,32,0.05);
      border: 1px solid rgba(200,160,32,0.22);
      border-radius: 3px;
      color: #a09070;
      font-family: inherit;
      font-size: .85rem;
      font-weight: 600;
      letter-spacing: .06em;
      cursor: pointer;
      transition: background .14s, color .14s, border-color .14s;
      min-height: 44px;
    }

    .online-lobby-tab:hover {
      background: rgba(200,160,32,0.10);
      color: #c8a020;
      border-color: rgba(200,160,32,0.45);
    }

    .online-lobby-tab.active {
      background: rgba(200,160,32,0.14);
      border-color: rgba(200,160,32,0.60);
      color: #e8c040;
    }

    /* ── Tab content ─────────────────────────────────────────────────────── */
    .online-lobby-content {
      min-height: 160px;
    }

    /* ── Status message ──────────────────────────────────────────────────── */
    .online-lobby-status {
      font-size: .84rem;
      color: #a09070;
      margin: 10px 0 0;
      min-height: 20px;
      letter-spacing: .04em;
    }

    .online-lobby-status.ok  { color: #6db36d; }
    .online-lobby-status.err { color: #d06060; }
    .online-lobby-status.warn { color: #c8a020; }

    /* ── Room code display ───────────────────────────────────────────────── */
    .online-lobby-code-display {
      display: flex;
      align-items: center;
      gap: 12px;
      margin: 16px 0;
    }

    .online-lobby-code-label {
      font-size: .8rem;
      color: #8a7858;
      letter-spacing: .06em;
      text-transform: uppercase;
      white-space: nowrap;
    }

    .online-lobby-code-value {
      font-size: 2rem;
      font-weight: 800;
      letter-spacing: .22em;
      color: #c8a020;
      text-shadow: 0 0 14px rgba(200,160,32,0.5);
      font-family: "Courier New", monospace;
      padding: 6px 12px;
      background: rgba(200,160,32,0.06);
      border: 1px solid rgba(200,160,32,0.25);
      border-radius: 3px;
    }

    /* ── Buttons ─────────────────────────────────────────────────────────── */
    .online-lobby-btn {
      min-height: 44px;
      min-width: 120px;
      padding: 10px 18px;
      background: rgba(200,160,32,0.08);
      border: 1px solid rgba(200,160,32,0.30);
      border-radius: 3px;
      color: #c8a020;
      font-family: inherit;
      font-size: .88rem;
      font-weight: 600;
      letter-spacing: .06em;
      cursor: pointer;
      transition: background .14s, border-color .14s, color .14s;
      margin-top: 12px;
    }

    .online-lobby-btn:hover:not(:disabled) {
      background: rgba(200,160,32,0.16);
      border-color: rgba(200,160,32,0.60);
      color: #e8c040;
    }

    .online-lobby-btn:disabled {
      opacity: 0.38;
      cursor: not-allowed;
    }

    .online-lobby-btn.primary {
      background: rgba(200,160,32,0.14);
      border-color: rgba(200,160,32,0.50);
    }

    /* ── Code input ──────────────────────────────────────────────────────── */
    .online-lobby-input {
      width: 100%;
      box-sizing: border-box;
      padding: 10px 14px;
      background: rgba(200,160,32,0.05);
      border: 1px solid rgba(200,160,32,0.28);
      border-radius: 3px;
      color: #e8d5b0;
      font-family: "Courier New", monospace;
      font-size: 1.4rem;
      font-weight: 700;
      letter-spacing: .18em;
      text-transform: uppercase;
      text-align: center;
      outline: none;
      min-height: 52px;
      margin-top: 4px;
    }

    .online-lobby-input:focus {
      border-color: rgba(200,160,32,0.60);
    }

    .online-lobby-unavailable {
      font-size: .84rem;
      color: #806040;
      font-style: italic;
    }
  `;
  document.head.appendChild(style);
}

// ─────────────────────────────────────────────────────────────────────────────
// OnlineLobbyPanel
// ─────────────────────────────────────────────────────────────────────────────

export default class OnlineLobbyPanel {
  constructor() {
    /** @type {HTMLElement|null} */
    this._backdrop = null;

    /** @type {'host'|'join'} */
    this._activeTab = 'host';

    /** @type {boolean} */
    this._visible = false;

    /** @type {boolean} — Set to false when WebSocket connection fails */
    this._available = true;

    /** @type {HTMLElement|null} */
    this._hostContent = null;

    /** @type {HTMLElement|null} */
    this._joinContent = null;

    /** @type {HTMLButtonElement|null} */
    this._startBtn = null;

    /** @type {HTMLButtonElement|null} */
    this._joinBtn = null;

    /** @type {HTMLInputElement|null} */
    this._codeInput = null;

    /** @type {Function} */
    this._keyHandler = this._onKey.bind(this);
  }

  // ─── Public API ────────────────────────────────────────────────────────────

  /**
   * Show the lobby panel. Attempts to connect to the WS server.
   */
  async show() {
    if (this._visible) return;

    injectStyles();
    this._build();
    this._backdrop.classList.add('visible');
    this._visible = true;
    document.addEventListener('keydown', this._keyHandler);

    DebugLog.info('[online] OnlineLobbyPanel opened');

    // Attempt to connect; disable panel if unavailable
    await OnlineCoopSystem.connect('ws://localhost:3001');
    if (!OnlineCoopSystem.isConnected) {
      this._markUnavailable();
    } else {
      this._bindCoopCallbacks();
    }
  }

  /**
   * Hide and clean up the lobby panel.
   */
  hide() {
    if (!this._visible) return;
    this._visible = false;
    document.removeEventListener('keydown', this._keyHandler);

    if (this._backdrop) {
      this._backdrop.remove();
      this._backdrop = null;
    }

    // Disconnect unless a game is in progress
    if (OnlineCoopSystem.isConnected && !OnlineCoopSystem.roomCode) {
      OnlineCoopSystem.disconnect();
    }

    DebugLog.info('[online] OnlineLobbyPanel closed');
  }

  /**
   * @returns {boolean}
   */
  isVisible() {
    return this._visible;
  }

  // ─── Build ─────────────────────────────────────────────────────────────────

  _build() {
    // Remove any stale instance
    document.getElementById('online-lobby-backdrop')?.remove();

    const backdrop = document.createElement('div');
    backdrop.id = 'online-lobby-backdrop';
    this._backdrop = backdrop;

    // Dismiss on backdrop click
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) this.hide();
    });

    const box = document.createElement('div');
    box.className = 'online-lobby-box';
    box.setAttribute('role', 'dialog');
    box.setAttribute('aria-label', 'Online Co-op Lobby');

    // Close button
    const closeBtn = document.createElement('button');
    closeBtn.type = 'button';
    closeBtn.className = 'online-lobby-close';
    closeBtn.textContent = '\u00D7';
    closeBtn.setAttribute('aria-label', 'Close');
    closeBtn.addEventListener('click', () => this.hide());
    box.appendChild(closeBtn);

    // Title
    const title = document.createElement('h2');
    title.className = 'online-lobby-title';
    title.textContent = 'Online Co-op';
    box.appendChild(title);

    // Tabs
    const tabBar = document.createElement('div');
    tabBar.className = 'online-lobby-tabs';

    const hostTab = this._makeTabBtn('Host Game', 'host');
    const joinTab = this._makeTabBtn('Join Game', 'join');
    tabBar.appendChild(hostTab);
    tabBar.appendChild(joinTab);
    box.appendChild(tabBar);

    // Content area
    const content = document.createElement('div');
    content.className = 'online-lobby-content';
    box.appendChild(content);
    this._contentArea = content;

    backdrop.appendChild(box);

    const mount = document.getElementById('ui-overlay') ?? document.body;
    mount.appendChild(backdrop);

    this._renderTab('host');
  }

  /**
   * @param {string} label
   * @param {'host'|'join'} tabId
   * @returns {HTMLButtonElement}
   */
  _makeTabBtn(label, tabId) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'online-lobby-tab' + (this._activeTab === tabId ? ' active' : '');
    btn.textContent = label;
    btn.dataset.tab = tabId;
    btn.addEventListener('click', () => this._renderTab(tabId));
    return btn;
  }

  /**
   * Render the content area for the given tab.
   * @param {'host'|'join'} tabId
   */
  _renderTab(tabId) {
    this._activeTab = tabId;

    // Update tab button active state
    if (this._backdrop) {
      this._backdrop.querySelectorAll('.online-lobby-tab').forEach((btn) => {
        btn.classList.toggle('active', btn.dataset.tab === tabId);
      });
    }

    this._contentArea.innerHTML = '';
    this._startBtn = null;
    this._joinBtn = null;
    this._codeInput = null;

    if (tabId === 'host') {
      this._buildHostTab();
    } else {
      this._buildJoinTab();
    }
  }

  _buildHostTab() {
    const content = this._contentArea;

    if (!this._available) {
      const msg = document.createElement('p');
      msg.className = 'online-lobby-unavailable';
      msg.textContent = 'Online play unavailable — could not connect to server.';
      content.appendChild(msg);
      return;
    }

    // "Create Room" button (shown before room is created)
    const createBtn = document.createElement('button');
    createBtn.type = 'button';
    createBtn.className = 'online-lobby-btn primary';
    createBtn.id = 'online-create-room-btn';
    createBtn.textContent = 'Create Room';
    createBtn.addEventListener('click', () => {
      createBtn.disabled = true;
      this._setHostStatus('Creating room...', 'warn');
      OnlineCoopSystem.createRoom();
    });
    content.appendChild(createBtn);

    // Room code display (hidden until room created)
    const codeRow = document.createElement('div');
    codeRow.className = 'online-lobby-code-display';
    codeRow.id = 'online-code-display';
    codeRow.style.display = 'none';

    const codeLabel = document.createElement('span');
    codeLabel.className = 'online-lobby-code-label';
    codeLabel.textContent = 'Room Code:';
    codeRow.appendChild(codeLabel);

    const codeValue = document.createElement('span');
    codeValue.className = 'online-lobby-code-value';
    codeValue.id = 'online-code-value';
    codeValue.textContent = '----';
    codeRow.appendChild(codeValue);
    content.appendChild(codeRow);

    // Status
    const status = document.createElement('p');
    status.className = 'online-lobby-status';
    status.id = 'online-host-status';
    status.textContent = 'Ready to host. Click "Create Room" to get a code.';
    content.appendChild(status);

    // Start Game button (hidden until guest joins)
    const startBtn = document.createElement('button');
    startBtn.type = 'button';
    startBtn.className = 'online-lobby-btn primary';
    startBtn.id = 'online-start-btn';
    startBtn.textContent = 'Start Game';
    startBtn.style.display = 'none';
    startBtn.disabled = true;
    startBtn.addEventListener('click', () => {
      OnlineCoopSystem.startGame();
      this._setHostStatus('Starting game...', 'ok');
      startBtn.disabled = true;
    });
    content.appendChild(startBtn);
    this._startBtn = startBtn;
  }

  _buildJoinTab() {
    const content = this._contentArea;

    if (!this._available) {
      const msg = document.createElement('p');
      msg.className = 'online-lobby-unavailable';
      msg.textContent = 'Online play unavailable — could not connect to server.';
      content.appendChild(msg);
      return;
    }

    const label = document.createElement('label');
    label.textContent = 'Enter Room Code:';
    label.style.cssText = 'display:block;font-size:.8rem;color:#8a7858;letter-spacing:.06em;text-transform:uppercase;margin-bottom:6px;';
    label.setAttribute('for', 'online-code-input');
    content.appendChild(label);

    const input = document.createElement('input');
    input.type = 'text';
    input.id = 'online-code-input';
    input.className = 'online-lobby-input';
    input.placeholder = 'XXXX';
    input.maxLength = 4;
    input.autocomplete = 'off';
    input.spellcheck = false;
    input.setAttribute('aria-label', 'Room code');

    input.addEventListener('input', () => {
      // Force uppercase
      const pos = input.selectionStart;
      input.value = input.value.toUpperCase().replace(/[^A-Z0-9]/g, '');
      input.setSelectionRange(pos, pos);

      if (this._joinBtn) {
        this._joinBtn.disabled = input.value.length !== 4;
      }
    });

    input.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' && input.value.length === 4) {
        this._joinBtn?.click();
      }
    });

    content.appendChild(input);
    this._codeInput = input;

    // Status
    const status = document.createElement('p');
    status.className = 'online-lobby-status';
    status.id = 'online-join-status';
    status.textContent = 'Enter the 4-character room code shared by the host.';
    content.appendChild(status);

    // Join button
    const joinBtn = document.createElement('button');
    joinBtn.type = 'button';
    joinBtn.className = 'online-lobby-btn primary';
    joinBtn.id = 'online-join-btn';
    joinBtn.textContent = 'Join Room';
    joinBtn.disabled = true;
    joinBtn.addEventListener('click', () => {
      const code = input.value.trim().toUpperCase();
      if (!OnlineCoopSystem.isValidRoomCode(code)) {
        this._setJoinStatus('Invalid room code — must be 4 alphanumeric characters.', 'err');
        return;
      }
      joinBtn.disabled = true;
      input.disabled = true;
      this._setJoinStatus('Joining room...', 'warn');
      OnlineCoopSystem.joinRoom(code);
    });
    content.appendChild(joinBtn);
    this._joinBtn = joinBtn;

    // Focus the input
    setTimeout(() => input.focus(), 50);
  }

  // ─── Status helpers ────────────────────────────────────────────────────────

  /**
   * @param {string} text
   * @param {'ok'|'err'|'warn'|''} [type='']
   */
  _setHostStatus(text, type = '') {
    const el = document.getElementById('online-host-status');
    if (!el) return;
    el.textContent = text;
    el.className = 'online-lobby-status' + (type ? ` ${type}` : '');
  }

  /**
   * @param {string} text
   * @param {'ok'|'err'|'warn'|''} [type='']
   */
  _setJoinStatus(text, type = '') {
    const el = document.getElementById('online-join-status');
    if (!el) return;
    el.textContent = text;
    el.className = 'online-lobby-status' + (type ? ` ${type}` : '');
  }

  // ─── Availability ──────────────────────────────────────────────────────────

  _markUnavailable() {
    this._available = false;
    DebugLog.warn('[online] WebSocket unavailable — disabling online features');
    // Re-render active tab to show unavailability message
    this._renderTab(this._activeTab);
  }

  // ─── OnlineCoopSystem callbacks ────────────────────────────────────────────

  _bindCoopCallbacks() {
    OnlineCoopSystem.onRoomCreated = (code) => {
      // Show code display
      const codeDisplay = document.getElementById('online-code-display');
      const codeValue = document.getElementById('online-code-value');
      const createBtn = document.getElementById('online-create-room-btn');
      if (codeDisplay) codeDisplay.style.display = 'flex';
      if (codeValue) codeValue.textContent = code;
      if (createBtn) createBtn.style.display = 'none';
      this._setHostStatus('Waiting for Player 2 to join...', 'warn');
      DebugLog.info(`[online] Room created; code=${code}`);
    };

    OnlineCoopSystem.onGuestJoined = () => {
      this._setHostStatus('Player 2 connected! Ready to start.', 'ok');
      if (this._startBtn) {
        this._startBtn.style.display = '';
        this._startBtn.disabled = false;
      }
      DebugLog.info('[online] Guest joined — Start button enabled');
    };

    OnlineCoopSystem.onRoomJoined = (code) => {
      this._setJoinStatus(`Joined room ${code}. Waiting for host to start...`, 'ok');
      if (this._codeInput) this._codeInput.disabled = true;
      DebugLog.info(`[online] Joined room ${code}`);
    };

    OnlineCoopSystem.onGameStarted = () => {
      DebugLog.info('[online] Game started — transitioning to CharCreate');
      this.hide();
      // Transition to character creation in online co-op mode
      import('../core/SceneManager.js').then((m) => {
        m.default.transition('charCreate', { coopMode: 'online' });
      });
    };

    OnlineCoopSystem.onError = (message) => {
      if (this._activeTab === 'host') {
        this._setHostStatus(`Error: ${message}`, 'err');
        const createBtn = document.getElementById('online-create-room-btn');
        if (createBtn) createBtn.disabled = false;
      } else {
        this._setJoinStatus(`Error: ${message}`, 'err');
        if (this._codeInput) this._codeInput.disabled = false;
        if (this._joinBtn) this._joinBtn.disabled = false;
      }
    };

    OnlineCoopSystem.onDisconnected = () => {
      if (this._visible) {
        this._setHostStatus('Connection lost.', 'err');
        this._setJoinStatus('Connection lost.', 'err');
        this._markUnavailable();
      } else {
        // Mid-game disconnect — show toast
        import('./Toast.js').then((m) => {
          m.default.show('Player 2 disconnected — reverting to single-player.', {
            type: 'warn',
            duration: 4000,
          });
        });
      }
    };
  }

  // ─── Keyboard ──────────────────────────────────────────────────────────────

  _onKey(e) {
    if (e.key === 'Escape') {
      e.stopPropagation();
      this.hide();
    }
  }
}
